-- name: CreateSession :one
-- Inserts a hosted session. id is an xid generated by the store; join_code
-- is the collision-checked short code minted by the domain layer. phase
-- defaults to 'lobby' at the DB level. A duplicate join_code trips the
-- UNIQUE constraint, which the store surfaces so the caller can regenerate.
INSERT INTO sessions (id, quiz_id, host_player_id, join_code)
VALUES (?, ?, ?, ?)
RETURNING *;

-- name: GetSession :one
SELECT *
FROM sessions
WHERE id = ?;

-- name: GetSessionByJoinCode :one
-- Resolves a typed/scanned room code to its session. join_code is UNIQUE so
-- this returns at most one row.
SELECT *
FROM sessions
WHERE join_code = ?;

-- name: JoinCodeExists :one
-- Cheap existence probe for a candidate join code so the generator can
-- regenerate on collision before paying for the INSERT.
SELECT EXISTS(SELECT 1 FROM sessions WHERE join_code = ?) AS code_exists;

-- name: UpsertSessionPlayer :one
-- Adds a player to a session's roster, or revives an existing row on
-- re-join (clearing left_at and refreshing last_seen_at + display_name).
-- A per-session display-name collision trips UNIQUE (session_id,
-- display_name); the caller retries with a petname. The (session_id,
-- player_id) UNIQUE makes the upsert idempotent for the same player.
INSERT INTO session_players (session_id, player_id, display_name)
VALUES (?, ?, ?)
ON CONFLICT (session_id, player_id)
    DO UPDATE SET display_name = excluded.display_name,
                  left_at      = NULL,
                  last_seen_at = CURRENT_TIMESTAMP
RETURNING *;

-- name: GetSessionPlayer :one
SELECT *
FROM session_players
WHERE session_id = ?
  AND player_id = ?;

-- name: SetSessionPlayerReady :execresult
-- Toggles a participant's ready flag and refreshes last_seen_at. Scoped to
-- (session_id, player_id) so it only ever touches the caller's own roster
-- row. The execresult lets the store map zero rows affected to "not a
-- participant".
UPDATE session_players
SET is_ready     = ?,
    last_seen_at = CURRENT_TIMESTAMP
WHERE session_id = ?
  AND player_id = ?;

-- name: ListSessionPlayers :many
-- The lobby roster in join order. Excludes players who have left (left_at
-- set, MP-10) so the lobby shows the current room.
SELECT *
FROM session_players
WHERE session_id = ?
  AND left_at IS NULL
ORDER BY joined_at, id;
